package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
	"time"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate email addresses, ensuring proper formatting of display names (including non-ASCII)
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct and encode subject line to support non-ASCII characters per RFC 2047
	rawSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.BEncoding.Encode("UTF-8", rawSubject)

	// Build email headers with required RFC 5322 fields and MIME configuration
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nDate: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: 8bit\r\n\r\n",
		from.String(),
		to.String(),
		time.Now().Format(time.RFC1123Z),
		encodedSubject,
	)

	// Generate HTML body with escaped user input to prevent XSS vulnerabilities and broken markup
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)

	// Ensure proper CRLF line endings for RFC 5322 compliance
	encodedBody := strings.ReplaceAll(htmlBody, "\n", "\r\n")

	// Combine headers and encoded body into the final RFC-compliant email message
	return headers + encodedBody, nil
}

