)
// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate and parse email addresses to ensure proper formatting and prevent invalid inputs
	from, err := mail.ParseAddress(fromAddr)
	if err!= nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err!= nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}
	// Encode subject using RFC 2047 to prevent header injection and handle non-ASCII characters
	rawSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", rawSubject)
	// Escape all user-provided content to prevent XSS vulnerabilities
	escapedUserName := template.HTMLEscapeString(userName)
	escapedSubject := template.HTMLEscapeString(subject)
	escapedFeedbackContent := template.HTMLEscapeString(feedbackContent)
	// Build HTML body with escaped content
	var htmlBuffer bytes.Buffer
	htmlBuffer.WriteString(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> `)
	htmlBuffer.WriteString(escapedUserName)
	htmlBuffer.WriteString(`</p>
  <p><strong>Subject:</strong> Feedback: `)
	htmlBuffer.WriteString(escapedSubject)
	htmlBuffer.WriteString(`</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">`)
	htmlBuffer.WriteString(escapedFeedbackContent)
	htmlBuffer.WriteString(`</pre>
  </div>
</body>
</html>`)
	// Use raw HTML body with 8-bit encoding (widely supported by modern SMTP servers)
	encodedBody := htmlBuffer.String()
	// Construct standard RFC 5322 headers with proper CRLF line endings
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: 8bit\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)
	// Combine headers and body to form the complete email
	return headers + encodedBody, nil
}

