package main
import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
	"time"
)
// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}
	// Validate from address (single address expected)
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	// Validate to addresses (supports comma-separated list of recipients)
	parsedTo, err := mail.ParseAddressList(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}
	// Build To header with properly encoded addresses (handles non-ASCII display names)
	toHeaderParts := make([]string, len(parsedTo))
	for i, addr := range parsedTo {
		toHeaderParts[i] = addr.String()
	}
	toHeader := strings.Join(toHeaderParts, ", ")
	// Format and encode subject line (RFC 2047 compliant for non-ASCII characters)
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)
	// Add mandatory RFC 5322 Date header
	dateHeader := time.Now().Format("Mon, 02 Jan 2006 15:04:05 -0700")
	// Construct email headers with proper MIME configuration
	headers := fmt.Sprintf(
		"Date: %s\r\n"+
			"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=UTF-8\r\n"+
			"Content-Transfer-Encoding: 8bit\r\n"+
			"\r\n",
		dateHeader,
		parsedFrom.String(),
		toHeader,
		encodedSubject,
	)
	// Build HTML body with escaped user input to prevent HTML injection and broken rendering
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)
	// Convert line endings to CRLF as required by RFC 5322
	htmlBody = strings.ReplaceAll(htmlBody, "\n", "\r\n")
	// Combine headers and body into final RFC-compliant message
	return headers + htmlBody, nil
}

