package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate email addresses, get properly encoded formatted addresses
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct and encode email subject per RFC 2047 for UTF-8 support
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.BEncoding.Encode("utf-8", emailSubject)

	// Construct email headers with proper MIME type and transfer encoding
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		from.String(),
		to.String(),
		encodedSubject,
	)

	// Escape user input to prevent HTML injection and ensure correct rendering
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped values
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	// Encode HTML body using quoted-printable for 7-bit compatibility and proper line endings
	var buf bytes.Buffer
	qw := quotedprintable.NewWriter(&buf)
	if _, err := qw.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode HTML body: %w", err)
	}
	if err := qw.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}
	encodedBody := buf.String()

	// Combine headers and encoded body to form the complete email
	emailMessage := headers + encodedBody

	return emailMessage, nil
}

