		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)
	// Encode HTML body to quoted-printable for safe 7-bit SMTP transport
	var buf bytes.Buffer
	qpWriter := quotedprintable.NewWriter(&buf)
	_, err = qpWriter.Write([]byte(htmlBody))
	if err!= nil {
		return "", fmt.Errorf("failed to encode email body: %w", err)
	}
	if err := qpWriter.Close(); err!= nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}
	encodedBody := buf.String()
	// Construct full email headers with all required fields
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nDate: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		from.String(),
		toHeaderValue,
		date,
		encodedSubject,
	)
	// Combine headers and encoded body into final RFC-compliant message
	emailMessage := headers + encodedBody
	return emailMessage, nil
}

