// BuildFeedbackEmail constructs an HTML-formatted email for user feedback
// Parameters:
//   - fromAddr: Sender email address
//   - toAddr: Recipient (support team) email address
//   - userName: Name of the user submitting feedback
//   - subject: Subject of the user's feedback
//   - feedbackContent: Detailed content of the user's feedback
// Returns:
//   - emailBody: Complete MIME email content ready to be sent via SMTP
//   - err: Error if any step of email construction fails
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required input parameters
	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}

	// Construct full email subject and encode it for UTF-8 compatibility
	fullSubject := fmt.Sprintf("User Feedback from %s: %s", userName, subject)
	encodedSubject := mime.QEncoding.Encode("utf-8", fullSubject)

	// Build standard MIME email headers
	var headersBuf bytes.Buffer
	headersBuf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	headersBuf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	headersBuf.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	headersBuf.WriteString("MIME-Version: 1.0\r\n")
	headersBuf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	headersBuf.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	headersBuf.WriteString("\r\n") // Empty line separates headers from body

	// Prepare data for template rendering
	templateData := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Render the HTML body from the template
	var bodyBuf bytes.Buffer
	if err := emailTemplate.Execute(&bodyBuf, templateData); err != nil {
		return "", fmt.Errorf("failed to render email template: %w", err)
	}

	// Combine headers and body to form the complete email
	fullEmail := headersBuf.String() + bodyBuf.String()

	return fullEmail, nil
}

