package main
import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
	"strings"
	"time"
)
// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation for required addresses
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}
	// Parse and validate email addresses to ensure proper formatting for headers
	// Automatically handles encoding of non-ASCII display names via Address.String()
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}
	// Construct and encode subject line per RFC 2047 to support non-ASCII characters
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)
	// Build RFC 5322 compliant headers
	// Includes required Date header, MIME type, and transfer encoding for HTML body
	headers := fmt.Sprintf(
		"From: %s\r\n"+
			"To: %s\r\n"+
			"Date: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=UTF-8\r\n"+
			"Content-Transfer-Encoding: quoted-printable\r\n"+
			"\r\n",
		from.String(),
		to.String(),
		time.Now().Format(time.RFC1123Z),
		encodedSubject,
	)
	// Construct HTML body with escaped user input to prevent HTML injection attacks
	// All user-provided values are escaped to ensure they are rendered as plain text
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)
	// Normalize line endings to CRLF as required by RFC 5322 and quoted-printable encoding
	// First convert any existing CRLF to LF to avoid duplicate CR characters, then convert all LF to CRLF
	htmlBody = strings.ReplaceAll(htmlBody, "\r\n", "\n")
	htmlBody = strings.ReplaceAll(htmlBody, "\n", "\r\n")
	// Encode HTML body using quoted-printable to ensure 7-bit compatibility
	// This handles non-ASCII characters and wraps long lines to meet RFC 5322 line length limits
	var encodedBodyBuf bytes.Buffer
	qpWriter := quotedprintable.NewWriter(&encodedBodyBuf)
	if _, err := qpWriter.Write([]byte(htmlBody)); err != nil {
		return "", fmt.Errorf("failed to encode body: %w", err)
	}
	if err := qpWriter.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}
	// Combine headers and encoded body to form the complete email message
	emailMessage := headers + encodedBodyBuf.String()
	return emailMessage, nil
}

