// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate From address list (RFC 5322 allows multiple From addresses, though uncommon)
	fromParsed, err := mail.ParseAddressList(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	// Format From addresses into canonical header value to prevent injection and ensure compliance
	fromHeaderParts := make([]string, len(fromParsed))
	for i, addr := range fromParsed {
		fromHeaderParts[i] = addr.String()
	}
	fromHeader := strings.Join(fromHeaderParts, ", ")

	// Validate To address list
	toParsed, err := mail.ParseAddressList(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}
	// Format To addresses into canonical header value to prevent injection and ensure compliance
	toHeaderParts := make([]string, len(toParsed))
	for i, addr := range toParsed {
		toHeaderParts[i] = addr.String()
	}
	toHeader := strings.Join(toHeaderParts, ", ")

	// Construct and RFC 2047 encode email subject to prevent header injection and support non-ASCII characters
	rawEmailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", rawEmailSubject)

	// Construct email headers with proper CRLF line endings per RFC 5322
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromHeader,
		toHeader,
		encodedSubject,
	)

	// Construct HTML body with all user input escaped to prevent HTML injection/XSS
