package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"mime/quotedprintable"
	"net/mail"
	"time"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Parse and validate email addresses to get properly formatted (encoded if needed) address strings
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct and encode subject line to support non-ASCII characters
	rawSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.BEncoding.Encode("utf-8", rawSubject)

	// Construct email headers with required RFC 5322 fields and MIME declarations
	headers := fmt.Sprintf(
		"Date: %s\r\nFrom: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: quoted-printable\r\n\r\n",
		time.Now().Format(time.RFC1123Z),
		from.String(),
		to.String(),
		encodedSubject,
	)

	// Escape user-provided content to prevent HTML injection and ensure proper rendering
	userNameEscaped := html.EscapeString(userName)
	subjectEscaped := html.EscapeString(subject)
	feedbackContentEscaped := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped user content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		userNameEscaped,
		subjectEscaped,
		feedbackContentEscaped,
	)

	// Encode HTML body to quoted-printable format for safe email transport
	var buf bytes.Buffer
	qw := quotedprintable.NewWriter(&buf)
	_, err = qw.Write([]byte(htmlBody))
	if err != nil {
		return "", fmt.Errorf("failed to encode email body: %w", err)
	}
	if err = qw.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}
	encodedBody := buf.String()

	// Combine headers and encoded body to form the complete email message
	emailMessage := headers + encodedBody

	return emailMessage, nil
